={
  "model": "claude-haiku",
  "messages": [
    {
      "role": "system",
      "content": "Generate social media posts for multiple platforms. Return JSON with keys: twitter (max 280 chars with emoji + hashtags), pinterest_title (60 chars), pinterest_description (500 chars with hashtags), facebook (2-3 paragraphs engaging), linkedin (professional tone). Each should be uniquely crafted for the platform."
    },
    {
      "role": "user",
      "content": "Article title: {{ $json.body.article.title }}\nExcerpt: {{ $json.body.article.excerpt }}\nURL: {{ $json.body.article.url }}\nKeyword: {{ $json.body.article.keyword }}\nSite: {{ $json.body.site_name }}\nTags: {{ JSON.stringify($json.body.article.tags || []) }}"
    }
  ],
  "max_tokens": 1000,
