parameters.jsCode:
// Parse the social posts from LLM response
const llmResponse = $input.first().json;
const choices = llmResponse.choices || [];
const content = choices[0]?.message?.content || '{}';

let socialPosts;
try {
  // Extract JSON from response
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  socialPosts = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  socialPosts = {
    twitter: `🔥 ${$('Distribution Webhook').first().json.body.article.title}\n\n👉 ${$('Distribution Webhook').first().json.body.article.url}`,
    pinterest_title: $('Distribution Webhook').first().json.body.article.title,
    pinterest_description: $('Distribution Webhook').first().json.body.article.excerpt,
    facebook: $('Distribution Webhook').first().json.body.article.excerpt,
    linkedin: $('Distribution Webhook').first().json.body.article.excerpt
  };
}

// Add metadata
socialPosts.article_url = $('Distribution Webhook').first().json.body.article.url;
socialPosts.site_id = $('Distribution Webhook').first().json.body.site_id;
socialPosts.site_name = $('Distribution Webhook').first().json.body.site_name;
socialPosts.generated_at = new Date().toISOString();

return [{ json: socialPosts }];

// Store the social posts for manual review/scheduling
// In production, this would connect to Buffer, Hootsuite, or direct APIs
const posts = $input.first().json;

// Log for monitoring
console.log(`Social posts generated for ${posts.site_name}:`);
console.log(`Twitter: ${posts.twitter?.substring(0, 100)}...`);
console.log(`Pinterest: ${posts.pinterest_title}`);
console.log(`Facebook: ${posts.facebook?.substring(0, 100)}...`);

// Forward to Contabo n8n for actual posting (bridge)
const bridgePayload = {
  action: 'distribute_social',
  payload: posts,
  source: 'arsenal',
  timestamp: new Date().toISOString()
};

return [{
  json: {
    success: true,
    social_posts: posts,
    bridge_payload: bridgePayload,
    message: `Social posts generated for ${posts.site_name}`
  }
}];
